    INSERT INTO internships (role, company_name, duration, description, technologies, status, company_logo, published) VALUES
    ('AI & Machine Learning Internship', 'Averixis Solutions', 'Aug 2025 – Dec 2025', 'Built strong foundations in AI & ML concepts, applied learning through practical tasks, and developed problem-solving skills aligned with industry expectations. Recognized under AICTE.', ARRAY['AI', 'Machine Learning', 'AICTE', 'Problem Solving', 'Data Analysis'], 'Completed', 'assets/internships/aiml-averixis.jpg', true),
    ('Front-End Web Development Internship', 'Edunet Foundation & IBM SkillsBuild', '6 Weeks', 'Gained hands-on experience building responsive and interactive web pages, working with HTML, CSS, JavaScript, and modern frameworks. Strengthened UI/UX design principles and deployment skills. In collaboration with AICTE.', ARRAY['HTML', 'CSS', 'JavaScript', 'UI/UX', 'Responsive Design', 'IBM SkillsBuild'], 'Completed', 'assets/internships/frontend-edunet.jpg', true),
    ('Emerging Technologies — AI & Cloud', 'Edunet Foundation & IBM', '4 Weeks', 'Strengthened skills in AI and Cloud platforms while gaining hands-on exposure to real-world applications. In collaboration with AICTE and IBM.', ARRAY['AI', 'Cloud Computing', 'IBM', 'AICTE', 'Emerging Tech'], 'Completed', 'assets/internships/ai-cloud-edunet.jpg', true),
    ('UI/UX Design Internship', 'Snestron Systems Pvt. Ltd.', 'Jul 2025 – Aug 2025', 'Enhanced understanding of user-centered design and creative problem solving. Completed a 4-week online internship contributing meaningfully to design projects.', ARRAY['UI/UX', 'User Research', 'Prototyping', 'Design Thinking', 'Figma'], 'Completed', 'assets/internships/uiux-snestron.jpg', true),
    ('Web Development Internship', 'Abhimo Technologies', '2026', 'Contributed to full-stack web development projects, building and debugging PHP backends and JavaScript frontends across multiple client products.', ARRAY['PHP', 'JavaScript', 'MySQL', 'Full-Stack', 'Debugging'], 'Completed', 'assets/internships/abhimo.jpg', true);
    INSERT INTO projects (title, short_description, full_description, technologies, skills, github_url, live_demo_url, project_image, featured, published, display_order, icon) VALUES
    ('Game Level Difficulty Balancer', 'An algorithmic solution that dynamically optimizes game difficulty curves using DAA principles — ensuring engaging, balanced gameplay.', 'Full implementation of priority queues, dynamic difficulty adjustment curves, and time complexity profiles to control gamer pacing in 2D platformers.', ARRAY['Python', 'Algorithms', 'DAA', 'Dynamic Programming'], ARRAY['Algorithm Design', 'Python'], 'https://github.com/sudeenjain/DAA-miniproject', NULL, NULL, false, true, 10, 'fa-gamepad'),
    ('Book Recommender System', 'An intelligent book recommendation engine built with Advanced Java that suggests titles based on user reading preferences and behavior patterns.', 'Includes content-based recommendations, user history vector models, and robust database support using JDBC.', ARRAY['Java', 'Advanced Java', 'Recommendation Engine'], ARRAY['Java'], 'https://github.com/sudeenjain/Adavanced-Java-BookRecommender', NULL, NULL, false, true, 20, 'fa-book'),
    ('IBM ML Recommender', 'A Python-based collaborative filtering system that leverages machine learning to predict user preferences and generate personalized recommendations.', 'Calculates cosine similarity and matrix factorization over high-density user reviews matrices.', ARRAY['Python', 'Machine Learning', 'Collaborative Filtering', 'IBM'], ARRAY['Machine Learning', 'Python'], 'https://github.com/sudeenjain/IBM-miniproject', NULL, NULL, false, true, 30, 'fa-cogs'),
    ('Interactive Recipe Finder', 'A dynamic web application enabling users to search, filter, and discover recipes with real-time ingredient matching and beautiful UI.', 'Uses external recipe search APIs, local storage caching, and sleek grid layout structure.', ARRAY['HTML', 'CSS', 'JavaScript', 'API Integration'], ARRAY['JavaScript', 'HTML/CSS'], 'https://github.com/sudeenjain/-interactive-recipe-finder', NULL, NULL, false, true, 40, 'fa-utensils'),
    ('Currency Converter', 'A real-time currency exchange tool that connects to live APIs — supporting 150+ currencies with instant conversion rates and clean interface.', 'Retrieves live exchange data from OpenExchangeRates API and stores currency mappings in custom visual lists.', ARRAY['JavaScript', 'REST API', 'Exchange Rates', 'Responsive'], ARRAY['JavaScript'], 'https://github.com/sudeenjain/currency-converter', NULL, NULL, false, true, 50, 'fa-exchange-alt'),
    ('Smart To-Do List', 'A Python-powered task management application with priority sorting, deadline tracking, and persistent storage for efficient productivity.', 'Uses JSON configuration file persistence, custom status updates, and priorities levels routing.', ARRAY['Python', 'File I/O', 'CLI', 'Task Management'], ARRAY['Python'], 'https://github.com/sudeenjain/to-do-list-in-python', NULL, NULL, false, true, 60, 'fa-tasks'),
    ('Gesture Flow', 'A gesture-controlled interface that interprets hand movements in real time to drive on-screen actions and interactions.', 'Processes raw camera footage inputs and maps points vectors using MediaPipe.', ARRAY['Python', 'Computer Vision', 'OpenCV'], ARRAY['Python', 'Machine Learning'], 'https://github.com/sudeenjain/guesture_flow', 'https://guestureflow.vercel.app/', NULL, false, true, 70, 'fa-hand-paper'),
    ('Attendance Tracker', 'A web-based attendance management system for recording, tracking, and reviewing attendance records efficiently.', 'Builds modular student visual charts, updates daily database fields, and provides tabular summaries.', ARRAY['JavaScript', 'Web App', 'Data Tracking'], ARRAY['JavaScript'], 'https://github.com/sudeenjain/attendence_tracker', 'https://attendance-tracker-eight-blush.vercel.app/', NULL, false, true, 80, 'fa-clipboard-check'),
    ('Movie Recommendation', 'A recommendation engine that suggests movies to users based on content similarity and viewing preferences.', 'Performs TF-IDF and bag-of-words vectorization on movies cast, directors, and genres columns.', ARRAY['Python', 'Machine Learning', 'Recommendation Engine'], ARRAY['Machine Learning', 'Python'], 'https://github.com/sudeenjain/Movie_Recommendation', 'https://movie-recommendation-plum-phi.vercel.app/', NULL, false, true, 90, 'fa-film'),
    ('Portfolio Website', 'An earlier version of this personal portfolio site, showcasing projects, certifications, and skills.', 'Static website built using responsive CSS grids, CSS custom variables, and basic interactive JS.', ARRAY['HTML', 'CSS', 'JavaScript'], ARRAY['JavaScript', 'HTML/CSS'], 'https://github.com/sudeenjain/portfolio', 'https://sudeenjain.github.io/portfolio/', NULL, false, true, 100, 'fa-user-circle'),
    ('FolioAI', 'An AI-powered portfolio assistant that helps generate and organize portfolio content automatically.', 'Allows users to customize section layouts and prompts LLMs to structure summary fields.', ARRAY['AI', 'JavaScript', 'Automation'], ARRAY['Artificial Intelligence', 'JavaScript'], 'https://github.com/sudeenjain/folioAI', 'https://portfolio-ai-eta-dusky.vercel.app/', NULL, false, true, 110, 'fa-robot'),
    ('CareerReady', 'A career-preparation platform helping users build job-readiness skills and track their progress.', 'Allows users to take mock aptitude tests and build custom resumes in real-time.', ARRAY['JavaScript', 'Web App', 'Career Tools'], ARRAY['JavaScript'], 'https://github.com/sudeenjain/CarrerReady', 'https://dist-steel-beta-55.vercel.app/#/landing', NULL, false, true, 120, 'fa-briefcase'),
    ('Product Recommendation', 'An AI-driven recommendation system that suggests products to users based on browsing and purchase behavior.', 'Performs user-based collaborative routing and groups products categories tags.', ARRAY['Python', 'AI', 'Recommendation Engine'], ARRAY['Machine Learning', 'Python'], 'https://github.com/sudeenjain/Product_Recommendation', 'https://ai-recommendation-system-gamma.vercel.app/', NULL, false, true, 130, 'fa-shopping-cart'),
    ('Connects The Dots', 'An algorithmic visualization project exploring graph connectivity and pathfinding concepts, built as a DAA mini-project.', 'Visualizes BFS, DFS, and Kruskal algorithms step-by-step.', ARRAY['Python', 'Algorithms', 'Graph Theory'], ARRAY['Algorithm Design', 'Python'], 'https://github.com/sudeenjain/Connect_the_Dots', 'https://daa-miniproject.vercel.app/', NULL, false, true, 140, 'fa-project-diagram'),
    ('Amazon Bestseller Recommender', 'A machine learning model that analyzes Amazon bestseller data to recommend similar high-performing products.', 'Performs exploratory data analysis on 10,000+ items and classifies them using random forests.', ARRAY['Python', 'Machine Learning', 'Data Analysis'], ARRAY['Machine Learning', 'Python'], 'https://github.com/sudeenjain/Amazon-Bestseller-Recommender', 'https://ibm-mini-project.vercel.app/', NULL, false, true, 150, 'fa-star'),
    ('AI Dictionary', 'An AI-powered dictionary tool offering smart word definitions, usage examples, and contextual understanding.', 'Interfaces with web APIs, processes NLP parameters, and parses dictionary definitions.', ARRAY['AI', 'NLP', 'JavaScript'], ARRAY['Artificial Intelligence', 'JavaScript'], 'https://github.com/sudeenjain/AI_dictonary', NULL, NULL, false, true, 160, 'fa-spell-check');
